// ═══════════════════════════════════════════════════════════════
// NODO: Delta Merger Engine (Enterprise Edition)
// OBIETTIVO: Fondere le modifiche dell'editor e i suggerimenti dell'AI
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// --- 1. SAFETY FIRST: CLONAZIONE E ASSEGNAZIONE SORGENTI ---
// Prendiamo i documenti originali e applichiamo i delta generati dall'AI
let finalKb = item.KbFragment ? JSON.parse(JSON.stringify(item.KbFragment)) : null;
let finalProduct = item.catalog ? JSON.parse(JSON.stringify(item.catalog)) : null;

// Il blueprint finale è quello che arriva direttamente dall'editor (già aggiornato dall'utente)
const finalBlueprint = item.modified_blueprint; 

const delta = item.delta_update;

// --- 2. HELPER FUNCTIONS (CORE ENGINE) ---

/**
 * Recupera il valore di una proprietà annidata
 */
function getNestedValue(obj, path) {
    if (!path || !obj) return undefined;
    return path.split('.').reduce((acc, part) => (acc && acc[part] !== undefined) ? acc[part] : undefined, obj);
}

/**
 * Risolve gli alias degli array (es: $[kb_sec]) trovando l'indice corretto
 */
function findIndexByFilter(currentArray, alias, filters) {
    if (!Array.isArray(currentArray) || !filters) return -1;

    // Trova il filtro associato all'alias corrente
    const filterObj = filters.find(f => {
        const key = Object.keys(f)[0];
        return key.startsWith(alias + '.');
    });

    if (!filterObj) return -1;

    const filterKeyFull = Object.keys(filterObj)[0]; 
    const expectedValue = filterObj[filterKeyFull];  
    const propertyName = filterKeyFull.substring(alias.length + 1);

    return currentArray.findIndex(el => {
        const val = getNestedValue(el, propertyName);
        return val === expectedValue;
    });
}

/**
 * Applica le patch stile MongoDB (Dot Notation + Array Filters)
 */
function applyUpdate(doc, path, value, filters) {
    if (!doc) return;

    const parts = path.split('.');
    let current = doc;

    for (let i = 0; i < parts.length; i++) {
        const part = parts[i];
        const isLast = i === parts.length - 1;

        // CASO ARRAY FILTER: es. "sections.$[kb_sec]"
        if (part.includes('$[')) {
            const alias = part.match(/\$\[(.*?)\]/)[1];
            if (Array.isArray(current)) {
                const idx = findIndexByFilter(current, alias, filters);
                if (idx !== -1) {
                    if (isLast) current[idx] = value;
                    else current = current[idx];
                } else return; 
            } else return;
        } 
        // CASO PROPRIETÀ STANDARD
        else {
            if (isLast) {
                current[part] = value;
            } else {
                if (current[part] === undefined) return; 
                current = current[part];
            }
        }
    }
}

// --- 3. ESECUZIONE PATCH SEMANTICHE ---

if (delta) {
    // A. Update Knowledge Base (KB_FRAGMENT)
    if (delta.kb_fragment_updates && delta.kb_fragment_updates.updates) {
        const updates = delta.kb_fragment_updates.updates;
        const filters = delta.kb_fragment_updates.array_filters || [];
        Object.keys(updates).forEach(path => {
            applyUpdate(finalKb, path, updates[path], filters);
        });
    }

    // B. Update Catalogo (CATALOG_ITEM)
    if (delta.catalog_updates && delta.catalog_updates.updates) {
        const updates = delta.catalog_updates.updates;
        const filters = delta.catalog_updates.array_filters || [];
        Object.keys(updates).forEach(path => {
            applyUpdate(finalProduct, path, updates[path], filters);
        });
    }
}

// --- 4. COSTRUZIONE OUTPUT ---

return {
    json: {
        // Documenti pronti per il salvataggio su MongoDB
        Final_KB_Fragment: finalKb,
        Final_Blueprint: finalBlueprint,
        Final_Product: finalProduct,

        // Metadati per log e UI
        sync_status: {
            blueprint_updated: true,
            kb_synced: !!delta?.kb_fragment_updates,
            catalog_synced: !!delta?.catalog_updates,
            reasoning: delta?.sync_summary?.reasoning || "Manutenzione strutturale blueprint"
        },

        // Pass-through del contesto originale
        owner_data: item.owner_data,
        transaction_summary: item.transaction_summary
    }
};

