// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero Dati Core
const owner = item.owner_data || {};
const blueprint = item.Final_Blueprint || {};
const sync = item.sync_status || {};

// 2. LOGICA SOMMA TRANSAZIONI (Sync + Compliance)
const txSync = item.transaction_summary || {};
const txLegal = item.transaction_summary_compliance || {};

const totalCredits = (txSync.credits_deducted || 0) + (txLegal.credits_deducted || 0);
const totalUsd = ((txSync.usd_cost || 0) + (txLegal.usd_cost || 0)).toFixed(4);
// Il saldo finale è quello dell'ultima transazione eseguita (txSync)
const finalBalance = txSync.final_balance || owner.credits_balance;

// Coordinate Telegram e Identificazione Asset
const sku = blueprint.service_sku || "N/A";
const mId = item.user_request?.message_id || "507";

// 3. Costruzione Dinamica dell'Impatto Architetturale
let impactList = [];
impactList.push(" ├ ⚙️ Architettura Step: <b>ALLINEATA</b>");

if (sync.kb_synced) {
    impactList.push(" ├ 🧠 Knowledge Base: <b>SINCRONIZZATA</b>");
}
if (sync.catalog_synced) {
    impactList.push(" ├ 📋 Requisiti Catalogo: <b>AGGIORNATI</b>");
}

let impactText = impactList.join("\n");

// 4. Localizzazione
const L = (owner.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
const t = {
    it: {
        title: "🛡️ <b>AUDIT COMPLIANCE COMPLETATO</b>",
        project: `ASSET: <b>${(blueprint.blueprint_name || sku).toUpperCase()}</b>`,
        header_impact: "📊 <b>IMPATTO SULL'ARCHITETTURA:</b>",
        header_reason: "🧠 <b>RAZIONALE DI ADEGUAMENTO AI:</b>",
        footer: `Investimento AI: <code>${totalCredits} Crediti</code> | Saldo: <b>${finalBalance}</b>`,
        btn_back: "⬅️ Torna alla Procedura"
    },
    en: {
        title: "🛡️ <b>COMPLIANCE AUDIT COMPLETED</b>",
        project: `ASSET: <b>${(blueprint.blueprint_name || sku).toUpperCase()}</b>`,
        header_impact: "📊 <b>ARCHITECTURAL IMPACT:</b>",
        header_reason: "🧠 <b>AI ALIGNMENT REASONING:</b>",
        footer: `AI Investment: <code>${totalCredits} Credit</code> | Balance: <b>${finalBalance}</b>`,
        btn_back: "⬅️ Back to Procedure"
    }
}[L];

// 5. Composizione Messaggio HTML
const messageText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${t.project}

${t.header_impact}
${impactText}

${t.header_reason}
<i>"${sync.reasoning}"</i>

━━━━━━━━━━━━━━━━━━━━
⛽ ${t.footer}`;

// 6. Payload Telegram
const telegramApiPayload = {
    method: "editMessageText",
    chat_id: owner.chat_id,
    message_id: mId,
    text: messageText,
    parse_mode: "HTML",
    reply_markup: {
        inline_keyboard: [
            [{ text: t.btn_back, callback_data: `get_active_sop_${sku}` }]
        ]
    }
};

return [{ json: { ...item, telegramApiPayload: telegramApiPayload, total_sync_credits: totalCredits } }];
